// src/components/Dashboard.js - Based on your design
import React, { useState, useEffect } from 'react';
import { TrendingUp, Users, FlaskConical, CheckCircle, Activity, BarChart3 } from 'lucide-react';

const Dashboard = ({ token }) => {
  const [stats, setStats] = useState({
    totalPatients: 0,
    totalTrials: 0,
    totalChecks: 0,
    eligibleCount: 0,
    recentActivity: []
  });

  useEffect(() => {
    loadDashboardData();
  }, [token]);

  const loadDashboardData = async () => {
    try {
      const [patientsRes, trialsRes, checksRes] = await Promise.all([
        fetch('http://localhost:8000/api/patients', {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch('http://localhost:8000/api/trials', {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch('http://localhost:8000/api/checks', {
          headers: { 'Authorization': `Bearer ${token}` }
        })
      ]);

      const patients = await patientsRes.json();
      const trials = await trialsRes.json();
      const checks = await checksRes.json();

      // Ensure data is always an array
      const patientsArray = Array.isArray(patients) ? patients : [];
      const trialsArray = Array.isArray(trials) ? trials : [];
      const checksArray = Array.isArray(checks) ? checks : [];
      
      const eligible = checksArray.filter(c => c.status === 'eligible').length;

      setStats({
        totalPatients: patientsArray.length,
        totalTrials: trialsArray.length,
        totalChecks: checksArray.length,
        eligibleCount: eligible,
        recentActivity: checksArray.slice(0, 5)
      });
      
      console.log('Dashboard loaded:', { patients: patientsArray.length, trials: trialsArray.length, checks: checksArray.length });
    } catch (error) {
      console.error('Failed to load dashboard:', error);
      setStats({
        totalPatients: 0,
        totalTrials: 0,
        totalChecks: 0,
        eligibleCount: 0,
        recentActivity: []
      });
    }
  };

  const styles = {
    container: {
      padding: '40px',
      color: 'white'
    },
    header: {
      marginBottom: '40px'
    },
    title: {
      fontSize: '48px',
      fontWeight: '800',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 50%, #a855f7 100%)',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent',
      marginBottom: '8px'
    },
    subtitle: {
      color: '#94a3b8',
      fontSize: '18px'
    },
    statsGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
      gap: '24px',
      marginBottom: '40px'
    },
    statCard: {
      background: 'linear-gradient(135deg, rgba(34, 211, 238, 0.1) 0%, rgba(59, 130, 246, 0.1) 100%)',
      backdropFilter: 'blur(10px)',
      padding: '32px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)',
      position: 'relative',
      overflow: 'hidden',
      transition: 'transform 0.3s ease, box-shadow 0.3s ease'
    },
    statIcon: {
      position: 'absolute',
      top: '20px',
      right: '20px',
      opacity: 0.2,
      transform: 'scale(1.5)'
    },
    statLabel: {
      fontSize: '14px',
      color: '#94a3b8',
      textTransform: 'uppercase',
      letterSpacing: '1px',
      marginBottom: '12px'
    },
    statValue: {
      fontSize: '48px',
      fontWeight: '800',
      color: 'white',
      marginBottom: '8px'
    },
    statChange: {
      fontSize: '14px',
      color: '#10b981',
      display: 'flex',
      alignItems: 'center',
      gap: '4px'
    },
    summarySection: {
      display: 'grid',
      gridTemplateColumns: '2fr 1fr',
      gap: '24px',
      marginBottom: '40px'
    },
    card: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '32px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)'
    },
    cardTitle: {
      fontSize: '24px',
      fontWeight: '700',
      marginBottom: '24px',
      display: 'flex',
      alignItems: 'center',
      gap: '12px'
    },
    activityItem: {
      padding: '16px',
      background: 'rgba(51, 65, 85, 0.5)',
      borderRadius: '12px',
      marginBottom: '12px',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center'
    },
    statusBadge: {
      padding: '6px 12px',
      borderRadius: '8px',
      fontSize: '12px',
      fontWeight: '600',
      textTransform: 'uppercase'
    }
  };

  const getStatusColor = (status) => {
    switch(status) {
      case 'eligible': return { bg: 'rgba(16, 185, 129, 0.2)', color: '#10b981' };
      case 'not_eligible': return { bg: 'rgba(239, 68, 68, 0.2)', color: '#ef4444' };
      default: return { bg: 'rgba(245, 158, 11, 0.2)', color: '#f59e0b' };
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div style={styles.title}>Dashboard Overview</div>
        <div style={styles.subtitle}>Welcome back! Here's your eligibility platform summary.</div>
      </div>

      <div style={styles.statsGrid}>
        <div 
          style={styles.statCard}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-8px)';
            e.currentTarget.style.boxShadow = '0 20px 40px rgba(34, 211, 238, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          <div style={styles.statIcon}>
            <Users size={80} color="#22d3ee" />
          </div>
          <div style={styles.statLabel}>Total Patients</div>
          <div style={styles.statValue}>{stats.totalPatients}</div>
          <div style={styles.statChange}>
            <TrendingUp size={16} />
            Active records
          </div>
        </div>

        <div 
          style={styles.statCard}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-8px)';
            e.currentTarget.style.boxShadow = '0 20px 40px rgba(139, 92, 246, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          <div style={styles.statIcon}>
            <FlaskConical size={80} color="#8b5cf6" />
          </div>
          <div style={styles.statLabel}>Clinical Trials</div>
          <div style={styles.statValue}>{stats.totalTrials}</div>
          <div style={styles.statChange}>
            <TrendingUp size={16} />
            Available trials
          </div>
        </div>

        <div 
          style={styles.statCard}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-8px)';
            e.currentTarget.style.boxShadow = '0 20px 40px rgba(59, 130, 246, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          <div style={styles.statIcon}>
            <Activity size={80} color="#3b82f6" />
          </div>
          <div style={styles.statLabel}>Checks Run</div>
          <div style={styles.statValue}>{stats.totalChecks}</div>
          <div style={styles.statChange}>
            <TrendingUp size={16} />
            Total predictions
          </div>
        </div>

        <div 
          style={styles.statCard}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = 'translateY(-8px)';
            e.currentTarget.style.boxShadow = '0 20px 40px rgba(16, 185, 129, 0.3)';
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = 'translateY(0)';
            e.currentTarget.style.boxShadow = 'none';
          }}
        >
          <div style={styles.statIcon}>
            <CheckCircle size={80} color="#10b981" />
          </div>
          <div style={styles.statLabel}>Eligible Patients</div>
          <div style={styles.statValue}>{stats.eligibleCount}</div>
          <div style={styles.statChange}>
            <TrendingUp size={16} />
            {stats.totalChecks > 0 ? `${((stats.eligibleCount / stats.totalChecks) * 100).toFixed(1)}% success rate` : 'No data'}
          </div>
        </div>
      </div>

      <div style={styles.summarySection}>
        <div style={styles.card}>
          <div style={styles.cardTitle}>
            <BarChart3 size={28} color="#22d3ee" />
            Recent Eligibility Predictions
          </div>
          {stats.recentActivity.length === 0 ? (
            <div style={{ color: '#94a3b8', textAlign: 'center', padding: '40px' }}>
              No predictions yet. Start checking eligibility!
            </div>
          ) : (
            stats.recentActivity.map((check, idx) => {
              const statusStyle = getStatusColor(check.status);
              return (
                <div key={idx} style={styles.activityItem}>
                  <div>
                    <div style={{ fontSize: '16px', fontWeight: '600', marginBottom: '4px' }}>
                      Check #{check.id}
                    </div>
                    <div style={{ fontSize: '14px', color: '#94a3b8' }}>
                      Score: {(check.overall_score * 100).toFixed(1)}% • Confidence: {check.confidence_score.toFixed(1)}%
                    </div>
                  </div>
                  <div style={{
                    ...styles.statusBadge,
                    background: statusStyle.bg,
                    color: statusStyle.color
                  }}>
                    {check.status.replace('_', ' ')}
                  </div>
                </div>
              );
            })
          )}
        </div>

        <div style={styles.card}>
          <div style={styles.cardTitle}>
            <Activity size={28} color="#8b5cf6" />
            Quick Stats
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <div>
              <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '8px' }}>
                Average Confidence
              </div>
              <div style={{ fontSize: '32px', fontWeight: '800', color: '#22d3ee' }}>
                {stats.totalChecks > 0 
                  ? `${(stats.recentActivity.reduce((sum, c) => sum + c.confidence_score, 0) / stats.recentActivity.length).toFixed(1)}%`
                  : '0%'
                }
              </div>
            </div>
            <div>
              <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '8px' }}>
                Success Rate
              </div>
              <div style={{ fontSize: '32px', fontWeight: '800', color: '#10b981' }}>
                {stats.totalChecks > 0 
                  ? `${((stats.eligibleCount / stats.totalChecks) * 100).toFixed(1)}%`
                  : '0%'
                }
              </div>
            </div>
            <div>
              <div style={{ fontSize: '14px', color: '#94a3b8', marginBottom: '8px' }}>
                Platform Status
              </div>
              <div style={{ 
                fontSize: '18px', 
                fontWeight: '700', 
                color: '#10b981',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <div style={{
                  width: '12px',
                  height: '12px',
                  borderRadius: '50%',
                  background: '#10b981',
                  boxShadow: '0 0 10px #10b981',
                  animation: 'pulse 2s infinite'
                }} />
                All Systems Operational
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
};

export default Dashboard;
